mapper.select:
SELECT * FROM email_verify_code
WHERE user_id = #{userId}
  AND email = #{email}
  AND email_type = #{emailType}
  AND scene = #{scene}
  AND status = 'PENDING'
ORDER BY id DESC
LIMIT 1

mapper.update:
UPDATE email_verify_code
SET status = 'CANCELED',
    update_time = CURRENT_TIMESTAMP(3)
WHERE user_id = #{userId}
  AND email_type = #{emailType}
  AND scene = #{scene}
  AND status = 'PENDING'
